import { Logger as NestLogger, RequestMethod } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { NestFactory } from '@nestjs/core';
import { DocumentBuilder, SwaggerModule } from '@nestjs/swagger';
import helmet from 'helmet';
import { Logger } from 'nestjs-pino';
import { AppModule } from './app.module';
import { AuditInterceptor } from './common/interceptors/audit.interceptor';
import { GlobalExceptionFilter } from './common/filters/global-exception.filter';
import { PrismaService } from './common/prisma/prisma.service';
import { RedisService } from './common/redis/redis.service';

/**
 * API bootstrap (README §2.5 A03/A05, §2.6, §2.7 graceful shutdown).
 * NOTE: started with `node --require ./dist/tracing.js dist/main.js` so the
 * OpenTelemetry SDK is initialized before any instrumented module loads.
 */
async function bootstrap(): Promise<void> {
  const app = await NestFactory.create(AppModule, { bufferLogs: true });
  app.useLogger(app.get(Logger));

  const config = app.get(ConfigService);
  const log = new NestLogger('Bootstrap');

  // All API routes under /api/v1; /metrics is served at the root (README §2.6).
  app.setGlobalPrefix('api/v1', {
    exclude: [{ path: 'metrics', method: RequestMethod.GET }],
  });

  // Security headers in one place (README §2.5 A03/A05 — do not split these).
  app.use(
    helmet({
      contentSecurityPolicy: { directives: { defaultSrc: ["'self'"] } },
      hsts: { maxAge: 31_536_000, includeSubDomains: true, preload: true },
    }),
  );
  app.enableCors({ origin: config.get<string>('CORS_ORIGIN', '*') });

  // One error pipeline + global audit logging (README §2.5 A09).
  app.useGlobalFilters(new GlobalExceptionFilter());
  app.useGlobalInterceptors(new AuditInterceptor());
  app.enableShutdownHooks();

  // Swagger only outside production (README §2.5 A05).
  if (config.get<string>('NODE_ENV') !== 'production') {
    const swaggerConfig = new DocumentBuilder()
      .setTitle('SmartCart API')
      .setDescription('SmartCart backend REST API (README §2.4).')
      .setVersion('v1')
      .addBearerAuth()
      .addApiKey({ type: 'apiKey', name: 'X-API-Key', in: 'header' }, 'api-key')
      .build();
    const document = SwaggerModule.createDocument(app, swaggerConfig);
    SwaggerModule.setup('api/docs', app, document);
  }

  const port = config.get<number>('PORT', 3000);
  await app.listen(port);
  log.log(`SmartCart API listening on :${port}`);

  // Graceful shutdown (README §2.7) — drain HTTP, then close resources.
  const gracefulShutdown = async (signal: string): Promise<void> => {
    log.log(`Received ${signal}, shutting down gracefully…`);
    await app.close(); // stop accepting new requests, finish in-flight
    await app.get(PrismaService).$disconnect();
    await app.get(RedisService).quit();
    process.exit(0);
  };
  process.on('SIGTERM', () => void gracefulShutdown('SIGTERM'));
  process.on('SIGINT', () => void gracefulShutdown('SIGINT'));
}

void bootstrap();
